(window.webpackJsonp=window.webpackJsonp||[]).push([[140],{767:function(n,e){n.exports="\x3c!-- \ntitle: 34-Flask\nsort: \n--\x3e \n# Flask入门\n\n## 上传数据\n\n```python\nfrom flask import Flask\nfrom flask import request\nimport time\n\n@server.route('/')\ndef index():\n    return '<h2>Flask Upload Running...</h2>'\n\n\n@server.route('/badusb')\ndef badusb():\n    mess = request.args.get('mess')\n    if mess != None:\n        now = time.strftime('%Y-%m-%d_%H:%M:%S')\n        sendmess([mess, now])\n        return '<h2>上传成功</h2>'\n    else:\n        return '''\n        <h2>BadUSB Upload Running...</h2>\n        <form action=\"/badusb\" method=\"get\" enctype=\"text/plain\">\n        Message：<input type=\"text\" name=\"mess\">\n        <input type=\"submit\" value=\"Submit\">\n        </form>\n        '''\nserver.run(host='127.0.0.1', port=8000)\n```\n\n## 上传文件\n\n```python\n@server.route('/upload', methods=['GET', 'POST'])\ndef upload():\n    if request.method == 'GET':\n        return '''\n        <form action=\"/upload\" method=\"post\" enctype=\"multipart/form-data\">\n        <input type=\"file\" id=\"upload\" name=\"upload\"></br>\n        Keygen: <input type=\"password\" name=\"keygen\">\n        <input type=\"submit\" value=\"Submit\">\n        '''\n    elif request.method == 'POST':\n        keygen = request.form.get('keygen')\n        fname = request.files['upload']\n        if keygen == 'passwd' and 'fname':\n            t = time.strftime('%Y-%m-%d_%H-%M-%S_')\n            name = t + fname.filename\n            fname.save('./upload/' + name)\n            return '<h2>Upload Success!</h2>'\n        else:\n            return '<h2>Please Select File!</h2>'\n\n```\n\n"}}]);